<?php $c=current_customer(); $flash=get_flash(); $rows=[]; try{$st=db()->prepare('SELECT * FROM tickets WHERE customer_id=? ORDER BY id DESC');$st->execute([$c['id']]);$rows=$st->fetchAll();}catch(Throwable $e){} ?>
<?php if($flash): ?><div class="auth-alert <?= e($flash['type']) ?>"><?= e($flash['message']) ?></div><?php endif; ?>
<div class="customer-panel-card"><h2>Destek Merkezi</h2><p>Teknik destek, satış, muhasebe veya domain işlemleri için talep oluşturun.</p></div>
<form class="customer-panel-card cp-form" method="post" action="<?= url('client/support') ?>"><h3>Yeni Destek Talebi</h3><div class="cp-form-grid"><label>Konu<input name="subject" required></label><label>Departman<select name="department"><option>Genel</option><option>Teknik Destek</option><option>Muhasebe</option><option>Domain</option><option>Satış</option></select></label><label>Öncelik<select name="priority"><option value="low">Düşük</option><option value="medium" selected>Normal</option><option value="high">Yüksek</option></select></label><label class="full">Mesaj<textarea name="message" rows="4" required></textarea></label></div><button class="cp-btn">Talebi Gönder</button></form>
